/**
 * Pixel-art lifter avatar for /landing, embedded as a self-contained data URI.
 *
 * The worker has no static-asset binding, so the 1024x1024 source (assets/liftty_avatar.png) is
 * downscaled to 160px (its rendered size) and inlined here. Displayed with image-rendering:pixelated,
 * so the chunky pixel-art look is intentional. Regenerate with sips -z 160 160 + base64 if the art changes.
 */
export const AVATAR_DATA_URI =
	"data:image/png;base64,";
